{
 "level": "A1–A2",
 "intro": "In this topic you will learn the <strong>five basic conjunctions</strong> of the English language: and, but, or, because, so — their meaning and rules of use.",
 "rules": [
 {
 "label": "And",
 "color": "emerald",
 "text": "<strong>And, and</strong> — connects similar ideas:",
 "example": "I like tea and coffee."
 },
 {
 "label": "But",
 "color": "rose",
 "text": "<strong>But, however</strong> — shows contrast:",
 "example": "I like tea, but I don't like coffee: raining."
 },
 {
 "label": "Or",
 "color": "blue",
 "text": "<strong>Or</strong> shows a choice:",
 "example": "Do you want tea or coffee?"
 },
 {
 "label": "Because",
 "color": "amber",
 "text": "<strong>Because</strong> gives a reason:",
 "example": "I stayed home because it was raining."
 },
 {
 "label": "So",
 "color": "purple",
 "text": "<strong>Therefore</strong> - shows the result:",
 "example": "It was raining, so I stayed home."
 }
 ]
}

{
 "title": "1. What are conjunctions?",
 "intro": "Conjunctions are words that connect:",
 "items": [
 {
 "label": "Words",
 "title": "Words",
 "subtitle": "tea and coffee / big but cheap"
 },
 {
 "label": "Phrases",
 "title": "Phrases",
 "subtitle": "in the morning or in the evening"
 },
 {
 "label": "Clauses",
 "title": "Sentences",
 "subtitle": "I came home and I cooked dinner."
 }
 ]
}

{
 "title": "2. AND — and, and (addition)",
 "sections": [
 {
 "label": "Meaning",
 "color": "emerald",
 "description": "<strong>And</strong> connects similar or equivalent elements. Adds information.",
 "examples": [
 {
 "en": "I have a cat and a dog.",
 "ua": "I have a cat and a dog."
 },
 {
 "en": "She is smart and beautiful.",
 "ua": "She is smart and beautiful."
 },
 {
 "en": "I came home and watched TV. I came home and watched TV.",
 "ua": "I came home and watched TV. I came home and watched TV."
 }
 ]
 },
 {
 "label": "Connect words",
 "color": "sky",
 "description": "<strong>And</strong> can connect nouns, adjectives, verbs.",
 "examples": [
 {
 "en": "bread and butter",
 "ua": "bread and butter"
 },
 {
 "en": "big and comfortable",
 "ua": "big and comfortable"
 },
 {
 "en": "run and jump",
 "ua": "run and jump"
 }
 ]
 },
 {
 "label": "Joining sentences",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "I woke up early, and I went for a run.",
 "ua": "I woke up early, and I went for a run."
 },
 {
 "en": "She cooked dinner, and he washed the dishes.",
 "ua": "She cooked dinner, and he washed the dishes."
 }
 ],
 "note": "A comma before <strong>and</strong> is optional if the sentences are short."
 }
 ]
}

{
 "title": "3. BUT - but, however (contrast)",
 "sections": [
 {
 "label": "Meaning",
 "color": "rose",
 "description": "<strong>But</strong> shows a contrast, opposition or unexpected result.",
 "examples": [
 {
 "en": "I like coffee, but I don't like tea.",
 "ua": "I like coffee, but I don't like tea."
 },
 {
 "en": "She is young but very experienced.",
 "ua": "She is young but very experienced."
 },
 {
 "en": "I tried hard, but I couldn't finish.",
 "ua": "I tried hard, but I couldn't finish."
 }
 ]
 },
 {
 "label": "Contrast",
 "color": "sky",
 "description": "<strong>But</strong> enters information that contradicts expectations.",
 "examples": [
 {
 "en": "The hotel was expensive, but it was worth it.",
 "ua": "The hotel was expensive, but it was worth it."
 },
 {
 "en": "He's rich, but he's not happy.",
 "ua": "He's rich, but he's not happy."
 }
 ]
 },
 {
 "label": "Punctuation",
 "color": "amber",
 "description": "<strong>but</strong> is usually preceded by a comma when two complete sentences are connected.",
 "examples": {
 "en": "I wanted to go, but it was too late.",
 "ua": "I wanted to go, but it was too late."
 },
 "note": "Without a comma: <em>small but cozy</em> (between the words)."
 }
 ]
}

{
 "title": "4. OR — or (choice)",
 "sections": [
 {
 "label": "The meaning",
 "color": "blue",
 "description": "<strong>Or</strong> shows an alternative, a choice between options.",
 "examples": [
 {
 "en": "Do you want tea or coffee?",
 "ua": "Do you want tea or coffee?"
 },
 {
 "en": "We can go today or tomorrow.",
 "ua": "We can go today or tomorrow."
 },
 {
 "en": "Is it true or false?",
 "ua": "Is it true or false?"
 }
 ]
 },
 {
 "label": "In questions",
 "color": "sky",
 "description": "<strong>Or</strong> is often used in questions to suggest a choice.",
 "examples": [
 {
 "en": "Do you prefer cats or dogs?",
 "ua": "Do you prefer cats or dogs?"
 },
 {
 "en": "Should I call or text you?",
 "ua": "Should I call or text you?"
 }
 ]
 },
 {
 "label": "In negatives",
 "color": "amber",
 "description": "In negative sentences, <strong>or</strong> is often used instead of <strong>and</strong>.",
 "examples": [
 {
 "en": "I don't like tea or coffee.",
 "ua": "I don't like tea or coffee."
 },
 {
 "en": "She doesn't eat meat or fish.",
 "ua": "She doesn't eat meat or fish."
 }
 ],
 "note": "Compare: <em>I like tea <strong>and</strong> coffee</em> vs <em>I don't like tea <strong>or</strong> coffee</em>."
 }
 ]
}

{
 "title": "5. BECAUSE",
 "sections": [
 {
 "label": "Meaning",
 "color": "amber",
 "description": "<strong>Because</strong> introduces a reason, explains why something happened.",
 "examples": [
 {
 "en": "I stayed home because it was raining.",
 "ua": "I stayed home because it was raining."
 },
 {
 "en": "She's tired because she worked all day.",
 "ua": "She's tired because she worked all day."
 },
 {
 "en": "I can't come because I'm busy.",
 "ua": "I can't come because I'm busy."
 }
 ]
 },
 {
 "label": "Sentence position",
 "color": "sky",
 "description": "A sentence with <strong>because</strong> can be at the beginning or at the end.",
 "examples": [
 {
 "en": "I stayed home because it was raining.",
 "ua": "I stayed home because it was raining."
 },
 {
 "en": "Because it was raining, I stayed home.",
 "ua": "Because it was raining, I stayed home."
 }
 ]
 },
 {
 "label": "Because vs Because of",
 "color": "emerald",
 "description": "<strong>Because</strong> + sentence, <strong>because of</strong> + noun.",
 "examples": [
 {
 "en": "I stayed home because it was raining.",
 "ua": "I stayed home because it was raining."
 },
 {
 "en": "I stayed home because of the rain.",
 "ua": "I stayed home because of the rain."
 }
 ],
 "note": "Do not confuse: <em>because</em> (because) vs <em>because of</em> (through)."
 }
 ]
}

{
 "title": "6. SO - therefore, therefore (result)",
 "sections": [
 {
 "label": "Meaning",
 "color": "purple",
 "description": "<strong>So</strong> introduces a result, a consequence of a previous action or situation.",
 "examples": [
 {
 "en": "It was raining, so I stayed home.",
 "ua": "It was raining, so I stayed home."
 },
 {
 "en": "I was hungry, so I made a sandwich.",
 "ua": "I was hungry, so I made a sandwich."
 },
 {
 "en": "She studied hard, so she passed the exam.",
 "ua": "She studied hard, so she passed the exam."
 }
 ]
 },
 {
 "label": "Because vs So",
 "color": "sky",
 "description": "<strong>Because</strong> = cause, <strong>So</strong> = result. Same information, different order.",
 "examples": [
 {
 "en": "I stayed home because it was raining.",
 "ua": "I stayed home because it was raining."
 },
 {
 "en": "It was raining, so I stayed home.",
 "ua": "It was raining, so I stayed home."
 }
 ]
 },
 {
 "label": "Punctuation",
 "color": "amber",
 "description": "Before <strong>so</strong> is usually followed by a comma.",
 "examples": [
 {
 "en": "The shop was closed, so we went home.",
 "ua": "The shop was closed, so we went home."
 },
 {
 "en": "I don't have money, so I can't buy it.",
 "ua": "I don't have money, so I can't buy it."
 }
 ]
 }
 ]
}

{
 "title": "7. Comparison table",
 "intro": "Five basic conjunctions and their functions:",
 "rows": [
 {
 "en": "AND",
 "ua": "AND",
 "note": "addition: I like tea and coffee."
 },
 {
 "en": "BUT",
 "ua": "BUT",
 "note": "contrast: I like tea, but I don't like coffee."
 },
 {
 "en": "OR",
 "ua": "OR",
 "note": "choice: Do you want tea or coffee?"
 },
 {
 "en": "BECAUSE",
 "ua": "BECAUSE",
 "note": "cause: I stayed home because it was raining."
 },
 {
 "en": "SO",
 "ua": "SO",
 "note": "result: It was raining, so I stayed home."
 }
 ],
 "warning": "📌 <strong>And, but, or</strong> are coordinating conjunctions. <strong>Because, so</strong> are subordinate/resultative."
}

{
 "title": "8. Punctuation with conjunctions",
 "intro": "When to put a comma before a conjunction:",
 "rows": [
 {
 "en": "Between words",
 "ua": "Between words",
 "note": "Without a comma: tea and coffee, big but cheap"
 },
 {
 "en": "Between clauses",
 "ua": "Between clauses",
 "note": "With a comma: I came, and she left."
 },
 {
 "en": "Short clauses",
 "ua": "Short clauses",
 "note": "Comma is optional: I came and she left."
 }
 ],
 "warning": "⚠️ <strong>but, so</strong> is usually preceded by a comma when connecting sentence."
}

{
 "title": "9. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Confusion between because and because of.",
 "wrong": "I stayed home because of it was raining.",
 "right": "​​​​ <span class=\"font-mono\">I stayed home because it was raining.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Using and instead of or in negatives.",
 "wrong": "I don't like tea and coffee.",
 "right": "​​​​​​​​ commas."
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Using because at the beginning without a comma.",
 "wrong": "Because it was raining I stayed home.",
 "right": "​​​​ <span class=\"font-mono\">Because it was raining, I stayed home.</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "So that instead of so (for the result).",
 "wrong": "I was tired so that I went to bed.",
 "right": "​​​​ <span class=\"font-mono\">I was tired, so I went to bed.</span>"
 }
 ]
}

{
 "title": "11. Practice",
 "select_title": "Exercise 1. Choose the correct conjunction",
 "select_intro": "Fill in the blank with the objectropriate conjunction.",
 "selects": [
 {
 "label": "I like tea ___ coffee. (and / but / or)",
 "prompt": "What conjunction?"
 },
 {
 "label": "She is smart ___ she doesn't study much. (and / but / because)",
 "prompt": "What conjunction?"
 },
 {
 "label": "Do you want pizza ___ pasta? (and / but / or)",
 "prompt": "What conjunction?"
 },
 {
 "label": "I stayed home ___ it was raining. (but/because/so) sentence",
 "prompt": "Which conjunction?"
 }
 ],
 "options": [
 "and",
 "but",
 "or",
 "because",
 "so"
 ],
 "input_title": "Exercise 2. Join the sentences",
 "input_intro": "Join the two sentences with the objectropriate conjunction.",
 "inputs": [
 {
 "before": "I was tired. I went to bed. (so) →",
 "after": ""
 },
 {
 "before": "She's rich. She's not happy. (but) →",
 "after": ""
 },
 {
 "before": "I can't come. I'm busy. (because) →",
 "after": ""
 }
 ],
 "rephrase_title": "Exercise 3. Correct the error",
 "rephrase_intro": "Find and correct the error in the use of the conjunction.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "I don't like tea and coffee.",
 "example_target": "I don't like tea or coffee."
 },
 {
 "original": "1. I stayed home because of it was cold.",
 "placeholder": "Fix the error"
 },
 {
 "original": "2. Because I was hungry, I made lunch. sentence",
 "placeholder": "Fix the mistake"
 }
 ]
}

